# Immediate mitigation via feature flag (per runbook RB-1042):
ff.payment.inventory_timeout_override=60000

# Permanent fix in PaymentServiceConfig.java:
@Bean
@Qualifier("inventoryRestTemplate")
public RestTemplate inventoryRestTemplate() {
    HttpComponentsClientHttpRequestFactory factory = new HttpComponentsClientHttpRequestFactory();
    factory.setReadTimeout(60000);    // was 30000 — must be >= 60000
    factory.setConnectTimeout(5000);
    return new RestTemplate(factory);
}

# Add circuit breaker (follow-up):
# In application.yml:
resilience4j:
  circuitbreaker:
    instances:
      inventory-service:
        slidingWindowSize: 20
        failureRateThreshold: 50
        waitDurationInOpenState: 10s
        permittedNumberOfCallsInHalfOpenState: 5
